<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="utf-8">
<title>Billiards</title>
<style>
  html, body {
    margin: 0; padding: 0;
    background: #1b1f24;
    color: #e8e8e8;
    font-family: "Segoe UI", Arial, sans-serif;
    user-select: none;
    -webkit-user-select: none;
  }
  #wrap {
    display: flex;
    flex-direction: column;
    align-items: center;
    padding: 14px;
    gap: 10px;
  }
  #hud {
    display: flex;
    align-items: center;
    gap: 16px;
    flex-wrap: wrap;
    justify-content: center;
  }
  #instructions {
    font-size: 14px;
    color: #cfd6dd;
    background: #262c33;
    border: 1px solid #3a424b;
    border-radius: 8px;
    padding: 8px 14px;
    line-height: 1.5;
    max-width: 860px;
    text-align: center;
  }
  #instructions b { color: #ffd97a; }
  button {
    background: #2f6f3f;
    color: #fff;
    border: 1px solid #1e4a29;
    border-radius: 8px;
    padding: 8px 18px;
    font-size: 15px;
    cursor: pointer;
  }
  button:hover { background: #388a4c; }
  button:active { transform: translateY(1px); }
  #powerbox {
    display: flex;
